const source = items[0].json;
const raw = source.choices?.[0]?.message?.content ?? source.output ?? source.data ?? '';

const normalize = (value) => {
  if (typeof value !== 'string') return value;
  const trimmed = value.trim();
  const fenced = trimmed.match(/^```(?:json)?\s*([\s\S]*?)\s*```$/i);
  if (fenced) return fenced[1].trim();
  return trimmed;
};

const parseContent = (value) => {
  const cleaned = normalize(value);
  const parsed = JSON.parse(cleaned);
  const topics = Array.isArray(parsed) ? parsed : parsed.topics;
  if (!Array.isArray(topics)) {
    throw new Error('Topic response did not contain a topics array.');
  }
  return topics;
};

const topics = parseContent(raw);
return topics.map((topic, index) => ({
  json: {
    ...topic,
    topic_index: index + 1,
    config: $items('Set Config', 0, 0)[0].json
  }
}));

const rawStyles = $json.config.imageStyles;
const styles = Array.isArray(rawStyles) ? rawStyles : JSON.parse(rawStyles);
const style = styles[Math.floor(Math.random() * styles.length)];
return [{
  json: {
    ...$json,
    image_style: style.image_style,
    style_prompt: style.style_prompt
  }
}];

const previous = $items('Assign Image Style', 0, $itemIndex)[0].json;
const current = items[0].json;

const normalize = (value) => {
  if (typeof value !== 'string') return value;
  const trimmed = value.trim();
  const fenced = trimmed.match(/^```(?:json)?\s*([\s\S]*?)\s*```$/i);
  return fenced ? fenced[1].trim() : trimmed;
};

if (current.error) {
  return [{
    json: {
      ...previous,
      generation_error: typeof current.error === 'string' ? current.error : JSON.stringify(current.error),
      status: 'REJECTED'
    }
  }];
}

const raw = current.choices?.[0]?.message?.content ?? current.output ?? current.data ?? '';
const parsed = JSON.parse(normalize(raw));

return [{
  json: {
    ...previous,
    hook: parsed.hook,
    caption: parsed.caption,
    hashtags: parsed.hashtags,
    cta: parsed.cta,
    image_prompt: parsed.image_prompt,
    score: Number(parsed.score ?? 0),
    status: 'READY'
  }
}];

const notes = [];
const baseStatus = $json.status || 'READY';
if ($json.generation_error) notes.push(`Copy generation failed: ${$json.generation_error}`);

const fallbackHook = $json.topic ? `${$json.topic}`.split(' ').slice(0, 6).join(' ') : 'Myrtle Beach Update';
const hook = ($json.hook || fallbackHook).replace(/[\r\n]+/g, ' ').trim();
const caption = $json.caption || `Useful Myrtle Beach real estate insight for ${$json.keyword || 'Myrtle Beach buyers'}.`;
const hashtags = $json.hashtags || '#myrtlebeach #myrtlebeachrealestate #southcarolinarealestate #coastalliving #realestatetips';
const cta = $json.cta || `Get a custom list of homes or investment properties in Myrtle Beach → ${$json.config.ctaLink}`;
const generatedPrompt = $json.image_prompt || `Vertical premium Myrtle Beach real estate marketing image with bold overlay text reading "${hook}".`;
const finalImagePrompt = [
  generatedPrompt,
  `Assigned style direction: ${$json.style_prompt}.`,
  `Bold overlay text displaying exactly: "${hook}".`,
  'Center or top-third text placement.',
  'Large, bold, high-contrast readable text.',
  'Vertical-friendly 9:16 composition for TikTok image posts.',
  'Premium realistic Myrtle Beach real estate aesthetic.',
  'No watermarks, no gibberish text, and no extra random signage unless naturally relevant to a real estate scene.'
].join(' ');

return [{
  json: {
    ...$json,
    hook,
    caption,
    hashtags,
    cta,
    score: Number.isFinite(Number($json.score)) ? Number($json.score) : 0,
    final_image_prompt: finalImagePrompt,
    notes: notes.join(' | '),
    status: baseStatus
  }
}];

const source = $items('Enhance Final Image Prompt', 0, $itemIndex)[0].json;
const imageResult = $items('Generate Image', 0, $itemIndex)[0]?.json || {};
const downloadResult = $items('Download Generated Image', 0, $itemIndex)[0]?.json || {};
const driveResult = items[0]?.json || {};

let status = source.status || 'READY';
const notes = [];
if (source.notes) notes.push(source.notes);

const generatedImageUrl = imageResult.output || '';
let imageUrl = '';

if (imageResult.error) {
  status = 'REJECTED';
  notes.push(`Image generation failed: ${typeof imageResult.error === 'string' ? imageResult.error : JSON.stringify(imageResult.error)}`);
}

if (downloadResult.error) {
  notes.push(`Image download failed: ${typeof downloadResult.error === 'string' ? downloadResult.error : JSON.stringify(downloadResult.error)}`);
}

if (driveResult.error) {
  notes.push(`Google Drive upload failed: ${typeof driveResult.error === 'string' ? driveResult.error : JSON.stringify(driveResult.error)}`);
  imageUrl = '';
} else if (driveResult.webViewLink || driveResult.webContentLink) {
  imageUrl = driveResult.webContentLink || driveResult.webViewLink;
} else if (generatedImageUrl && !driveResult.error) {
  imageUrl = generatedImageUrl;
}

const now = new Date();
const createdAt = now.toISOString();
const postDate = new Intl.DateTimeFormat('en-CA', { timeZone: 'America/New_York' }).format(now);
const randomId = Math.random().toString(36).slice(2, 8).toUpperCase();
const contentId = `MB-${postDate.replace(/-/g, '')}-${String(source.topic_index || 0).padStart(2, '0')}-${randomId}`;

return [{
  json: {
    content_id: contentId,
    created_at: createdAt,
    post_date: postDate,
    category: source.category || '',
    topic: source.topic || '',
    keyword: source.keyword || '',
    hook: source.hook || '',
    image_style: source.image_style || '',
    image_prompt: source.final_image_prompt || source.image_prompt || '',
    image_url: imageUrl,
    caption: source.caption || '',
    hashtags: source.hashtags || '',
    cta: source.cta || `Get a custom list of homes or investment properties in Myrtle Beach → ${source.config.ctaLink}`,
    status,
    score: Number.isFinite(Number(source.score)) ? Number(source.score) : 0,
    notes: notes.filter(Boolean).join(' | ')
  }
}];

const source = items[0].json;
const now = new Date();
const createdAt = now.toISOString();
const postDate = new Intl.DateTimeFormat('en-CA', { timeZone: 'America/New_York' }).format(now);
const randomId = Math.random().toString(36).slice(2, 8).toUpperCase();
const contentId = `MB-${postDate.replace(/-/g, '')}-${String(source.topic_index || 0).padStart(2, '0')}-${randomId}`;
const fallbackNotes = [source.notes, source.generation_error && `Copy generation failed: ${source.generation_error}`].filter(Boolean).join(' | ');

return [{
  json: {
    content_id: contentId,
    created_at: createdAt,
    post_date: postDate,
    category: source.category || '',
    topic: source.topic || '',
    keyword: source.keyword || '',
    hook: source.hook || '',
    image_style: source.image_style || '',
    image_prompt: source.final_image_prompt || source.image_prompt || '',
    image_url: '',
    caption: source.caption || '',
    hashtags: source.hashtags || '',
    cta: source.cta || `Get a custom list of homes or investment properties in Myrtle Beach → ${source.config.ctaLink}`,
    status: 'REJECTED',
    score: Number.isFinite(Number(source.score)) ? Number(source.score) : 0,
    notes: fallbackNotes || 'Post package could not be generated.'
  }
}];
